[Fact]
public void ConsoleTable_ShouldSupportInitializationFromPocoAndManualSetup()
{
    // Arrange - POCO initialization
    var pocoItems = new[]
    {
        new { Id = 101, Name = "POCO Item" }
    };

    // Act - Initialize via From<T>
    var pocoTable = ConsoleTable.From(pocoItems);

    // Assert - Verify POCO structure
    Assert.Equal(2, pocoTable.Columns.Count);
    Assert.Equal("Id", pocoTable.Columns[0]);
    Assert.Equal("Name", pocoTable.Columns[1]);
    Assert.Single(pocoTable.Rows);
    Assert.Equal(101, pocoTable.Rows[0][0]);

    // Arrange - Manual initialization
    var manualTable = new ConsoleTable("ManualCol1", "ManualCol2");

    // Act - Add data manually
    manualTable.AddRow("Value 1", "Value 2");

    // Assert - Verify Manual structure
    Assert.Equal(2, manualTable.Columns.Count);
    Assert.Equal("ManualCol1", manualTable.Columns[0]);
    Assert.Equal("ManualCol2", manualTable.Columns[1]);
    Assert.Single(manualTable.Rows);
    Assert.Equal("Value 1", manualTable.Rows[0][0]);
}

[Fact]
public void TableShouldSupportConfigurableVisualStylesAndNumericAlignment()
{
    var data = new[] 
    {
        new { Name = "Test Product", Stock = 500 }
    };

    var writer = new System.IO.StringWriter();
    var table = ConsoleTable.From(data)
        .Configure(options => 
        {
            options.NumberAlignment = Alignment.Right;
            options.OutputTo = writer;
            options.EnableCount = false;
        });

    // Verify the business rule requirement for supporting the 'Alternative' visual style
    table.Write(ConsoleTables.Format.Alternative);
    var output = writer.ToString();

    // Assertion for structural elements of the table
    Assert.Contains("Name", output);
    Assert.Contains("Stock", output);
    Assert.Contains("Test Product", output);

    // Verification of numeric alignment (Right): 
    // In the 'Stock' column (header length 5), the value '500' (length 3) should 
    // have leading spaces if right-aligned as per the GetNumberAlignment logic.
    Assert.Contains("  500 ", output);
}

[Fact]
        public void ShouldEnforceColumnDefinitionAndCountMatchingWhenAddingRows()
        {
            var tableNoColumns = new ConsoleTable();
            var exceptionNoColumns = Assert.Throws<Exception>(() => tableNoColumns.AddRow("data"));

            Assert.Equal("Please set the columns first", exceptionNoColumns.Message);

            var tableWithColumns = new ConsoleTable("Col1", "Col2");
            var exceptionMismatch = Assert.Throws<Exception>(() => tableWithColumns.AddRow("data1", "data2", "data3"));

            Assert.Equal("The number columns in the row (2) does not match the values (3)", exceptionMismatch.Message);
        }

[Fact]
public void CellContentExceedingMaxWidthShouldWrapAndPrioritizeDelimiters()
{
    // Arrange
    // Create a table with a column named "Message"
    var table = new ConsoleTable("Message");

    // Set a small MaxWidth to trigger wrapping logic
    table.MaxWidth = 10;

    // Explicitly set the delimiter and enable the count for verification
    table.SetWordBreakDelimiter(' ');
    table.Configure(o => o.EnableCount = true);

    // "Breaking News" is 13 characters long, which exceeds MaxWidth (10)
    // The logic should find the last space (' ') within the first 10 characters (index 8)
    table.AddRow("Breaking News");

    // Act
    // ToString() triggers SetFormats(), which performs the wrapping logic
    var output = table.ToString();

    // Assert
    // Verify that "Breaking" (the first part) and "News" (the wrapped part) are both in the output
    Assert.Contains("Breaking", output);
    Assert.Contains("News", output);

    // Verify that the wrapping logic correctly inserted a new row into the internal Rows collection,
    // resulting in a total row count of 2 instead of 1.
    Assert.Contains("Count: 2", output);
}

[Fact]
public void NumericColumnsShouldBeRightAlignedBasedOnConfiguration()
{
    var list = new List<User>
    {
        new User { Name = "Alice", Age = 25 },
        new User { Name = "Bob", Age = 7 }
    };

    var tableString = ConsoleTable
        .From(list)
        .Configure(o => o.NumberAlignment = Alignment.Right)
        .ToString();

    Assert.Contains("| Alice |  25 |", tableString);
    Assert.Contains("| Bob   |   7 |", tableString);
}

[Fact]
public void ShouldNotDisplayCountWhenEnableCountIsFalse()
{
    var options = new ConsoleTableOptions
    {
        Columns = new[] { "TestColumn" },
        EnableCount = false
    };
    var table = new ConsoleTable(options);
    table.AddRow("TestValue");

    var output = table.ToString();

    Assert.DoesNotContain("Count:", output);
}

[Fact]
        public void TableColumnAlignmentShouldBeConfigurableForNumericDataTypes()
        {
            var data = new[]
            {
                new { Product = "Gadget", Stock = 125 }
            };

            var table = ConsoleTable
                .From(data)
                .Configure(options => options.NumberAlignment = Alignment.Right)
                .ToString();

            // The column 'Stock' has a header length of 5.
            // The value '125' has a length of 3.
            // For Alignment.Right, GetNumberAlignment returns an empty string ("") 
            // resulting in a format string like {1, 5} which right-aligns the number.
            // The expected row segment is |    125 |
            Assert.Contains("| Gadget  |   125 |", table);
        }

[Fact]
public void ShouldNotDisplayCountSummaryWhenEnableCountIsDisabled()
{
    var table = new ConsoleTable("one", "two")
        .AddRow(1, 2)
        .Configure(o => o.EnableCount = false)
        .ToString();

    Assert.DoesNotContain("Count:", table);
}

[Fact]
public void FromDictionary_ShouldAutomaticallyGenerateTableWithKeysAsRowHeadersAndInnerKeysAsColumnHeaders()
{
    // Arrange
    var dictionary = new Dictionary<string, Dictionary<string, object>>
    {
        {
            "Row1", new Dictionary<string, object>
            {
                { "ColA", "Val1" },
                { "ColB", "Val2" }
            }
        },
        {
            "Row2", new Dictionary<string, object>
            {
                { "ColA", "Val3" },
                { "ColB", "Val4" }
            }
        }
    };

    // Act
    var table = ConsoleTable.FromDictionary(dictionary);
    var result = table.ToMarkDownString();

    // Assert
    // Based on library logic: 
    // Column 0 is empty header vs RowKeys (Row1/Row2 are 4 chars). Width = 4.
    // Column 1 is Header "ColA" (4) vs "Val1"/"Val3" (4). Width = 4.
    // Column 2 is Header "ColB" (4) vs "Val2"/"Val4" (4). Width = 4.
    var expected = """
                   |      | ColA | ColB |
                   |------|------|------|
                   | Row1 | Val1 | Val2 |
                   | Row2 | Val3 | Val4 |

                   """;

    Assert.Equal(expected, result);
}

[Fact]
        public void ShouldSupportFormattingFeaturesAcrossMultipleOutputStyles()
        {
            var table = new ConsoleTable("Name", "Value")
                .AddRow("User 哈哈", 1)
                .AddRow("User 2", 100)
                .Configure(o =>
                {
                    o.NumberAlignment = Alignment.Right;
                    o.EnableCount = true;
                });

            var markdown = table.ToMarkDownString();
            var standard = table.ToString();
            var minimal = table.ToMinimalString();

            // Verify Markdown style with Unicode-aware alignment and numeric right-alignment
            Assert.Contains("| User 哈哈 |     1 |", markdown);
            Assert.Contains("| User 2    |   100 |", markdown);

            // Verify Standard boxed style contains the Unicode data and row count footer
            Assert.Contains("User 哈哈", standard);
            Assert.Contains("Count: 2", standard);

            // Verify Minimal style content
            Assert.Contains("User 哈哈", minimal);
            Assert.DoesNotContain("|", minimal);
        }

[Fact]
        public void ShouldCorrectlyInitializeFromAllSupportedDataFormats()
        {
            // 1. Collections of objects (IEnumerable<T>)
            var enumerableData = new[] { new { Id = 1, Name = "Test" } };
            var tableFromEnumerable = ConsoleTable.From(enumerableData);

            // 2. DataTables
            var dataTable = new System.Data.DataTable();
            dataTable.Columns.Add("Id");
            dataTable.Rows.Add(1);
            var tableFromDataTable = ConsoleTable.From(dataTable);

            // 3. Nested dictionaries (Dictionary<string, Dictionary<string, object>>)
            var dictionaryData = new System.Collections.Generic.Dictionary<string, System.Collections.Generic.Dictionary<string, object>>
            {
                { "Row1", new System.Collections.Generic.Dictionary<string, object> { { "Id", 1 } } }
            };
            var tableFromDictionary = ConsoleTable.FromDictionary(dictionaryData);

            // 4. Multi-dimensional object arrays (Object[][])
            var arrayData = new object[][]
            {
                new object[] { "Id" },
                new object[] { 1 }
            };
            var tableFromArray = ConsoleTable.From(arrayData);

            // Assert all instances were created successfully
            Assert.NotNull(tableFromEnumerable);
            Assert.NotNull(tableFromDataTable);
            Assert.NotNull(tableFromDictionary);
            Assert.NotNull(tableFromArray);
        }

